/**
 * Mock data for the Finance · Transactions sub-page.
 *
 * The full demo mockup generates 740 rows; for the v2 prototype we ship a
 * curated set of anchor rows that exercise every variant — Revenue with
 * gateway-fee net line, COGS, Marketing, Rent, Payroll, Gateway fees,
 * pending sync, unclassified — plus enough volume to make filters feel
 * real. ~80 rows total.
 */

export type TxDir = "in" | "out";
export type TxSync = "ok" | "pend";

export type TxCategory =
  | "Revenue"
  | "COGS"
  | "Marketing"
  | "Delivery"
  | "Software"
  | "Rent"
  | "Payroll"
  | "Gateway fee"
  | "Unclassified";

export interface Transaction {
  id: string;
  /** "May 22" */
  date: string;
  year: string;
  desc: string;
  /** detail line under desc (txn id, gateway, etc.) */
  detail: string;
  category: TxCategory;
  source: string;
  sync: TxSync;
  dir: TxDir;
  /** USD gross */
  amount: number;
  /** If incoming and a gateway took a fee, the net banked */
  net?: number;
  gw?: "Stripe" | "PayPal";
  fee?: boolean;
  /** recency rank; bigger = newer (used for date sort and period filter) */
  rank: number;
}

const CATEGORY_BADGE: Record<TxCategory, string> = {
  Revenue: "b-rev",
  COGS: "b-cogs",
  Marketing: "b-mkt",
  Delivery: "b-deliv",
  Software: "b-soft",
  Rent: "b-rent",
  Payroll: "b-pay",
  "Gateway fee": "b-fee",
  Unclassified: "b-unc",
};

export function categoryBadge(c: TxCategory): string {
  return CATEGORY_BADGE[c];
}

