export const TRANSACTIONS: Transaction[] = anchors.map((a, i) => ({
  ...a,
  rank: anchors.length - i,
}));

export const txMetrics = {
  moneyIn: TRANSACTIONS.filter((t) => t.dir === "in").reduce((a, t) => a + t.amount, 0),
  moneyOut: TRANSACTIONS.filter((t) => t.dir === "out").reduce((a, t) => a + t.amount, 0),
  total: TRANSACTIONS.length,
  pending: TRANSACTIONS.filter((t) => t.sync === "pend").length,
};

