"use client";

import { useMemo, useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { BridgePrimaryButton } from "@/features/bridge/components/BridgePrimaryButton";
import {
  TRANSACTIONS,
  txMetrics,
  txAI,
  gatewayFees,
  categoryBadge,
  type Transaction,
} from "@/features/finance/api/finance-transactions-data";
import "./transactions.css";

const fmtUSD = (v: number) => `$${Math.round(v).toLocaleString()}`;

type DirFilter = "all" | "in" | "out";
type SyncFilter = "all" | "pend";
type SortKey = "date" | "desc" | "cat" | "src" | "sync" | "amt";

const PERIOD_LABELS = ["Last 7 days", "This month", "Last 90 days", "Year to date"];

export default function TransactionsPage() {
  const [periodIdx, setPeriodIdx] = useState(1); // This month
  const [search, setSearch] = useState("");
  const [dirFilter, setDirFilter] = useState<DirFilter>("all");
  const [syncFilter, setSyncFilter] = useState<SyncFilter>("all");
  const [sortKey, setSortKey] = useState<SortKey>("date");
  const [sortDir, setSortDir] = useState<1 | -1>(-1);

  const rows = useMemo(() => {
    const q = search.toLowerCase();
    const filtered = TRANSACTIONS.filter((t) => {
      if (dirFilter !== "all" && t.dir !== dirFilter) return false;
      if (syncFilter === "pend" && t.sync !== "pend") return false;
      if (q) {
        const haystack = `${t.desc} ${t.detail} ${t.category} ${t.source}`.toLowerCase();
        if (!haystack.includes(q)) return false;
      }
      return true;
    });
    return filtered.sort((a, b) => {
      let av: string | number;
      let bv: string | number;
      switch (sortKey) {
        case "date":
          av = a.rank;
          bv = b.rank;
          break;
        case "amt":
          av = a.dir === "in" ? a.amount : -a.amount;
          bv = b.dir === "in" ? b.amount : -b.amount;
          break;
        case "desc":
          av = a.desc.toLowerCase();
          bv = b.desc.toLowerCase();
          break;
        case "cat":
          av = a.category.toLowerCase();
          bv = b.category.toLowerCase();
          break;
        case "src":
          av = a.source.toLowerCase();
          bv = b.source.toLowerCase();
          break;
        case "sync":
          av = a.sync;
          bv = b.sync;
          break;
      }
      if (typeof av === "number" && typeof bv === "number") return (av - bv) * sortDir;
      return String(av).localeCompare(String(bv)) * sortDir;
    });
  }, [search, dirFilter, syncFilter, sortKey, sortDir]);

  const handleSort = (k: SortKey) => {
    if (sortKey === k) setSortDir((d) => (d === 1 ? -1 : 1));
    else {
      setSortKey(k);
      setSortDir(k === "date" || k === "amt" ? -1 : 1);
    }
  };

  const filteredIn = rows.filter((t) => t.dir === "in").reduce((a, t) => a + t.amount, 0);
  const filteredOut = rows.filter((t) => t.dir === "out").reduce((a, t) => a + t.amount, 0);
  const filteredNet = filteredIn - filteredOut;

  return (
    <div className="finance-transactions-page">
      <DeptHeader
        dept="finance"
        title="Transactions"
        meta={
          <>
            <span className="live">Live</span> · Every money movement, netted and categorized · from ledger
          </>
        }
        actions={
          <>
            <button className="btn-util">Export</button>
            <BridgePrimaryButton dept="finance">Review unclassified →</BridgePrimaryButton>
          </>
        }
      />

      <PeriodTabs labels={PERIOD_LABELS} activeIndex={periodIdx} onChange={setPeriodIdx} />

      {/* Metric strip */}
      <div className="metric-strip">
        <div className="metric">
          <div className="metric-l">Money in</div>
          <div className="metric-v in">{fmtUSD(txMetrics.moneyIn)}</div>
          <div className="metric-s">
            {TRANSACTIONS.filter((t) => t.dir === "in").length} entries
          </div>
        </div>
        <div className="metric">
          <div className="metric-l">Money out</div>
          <div className="metric-v out">{fmtUSD(txMetrics.moneyOut)}</div>
          <div className="metric-s">
            {TRANSACTIONS.filter((t) => t.dir === "out").length} entries
          </div>
        </div>
        <div className="metric">
          <div className="metric-l">Net movement</div>
          <div className="metric-v">
            {txMetrics.moneyIn - txMetrics.moneyOut >= 0 ? "+" : "−"}
            {fmtUSD(Math.abs(txMetrics.moneyIn - txMetrics.moneyOut))}
          </div>
          <div className="metric-s">{txMetrics.total} entries total</div>
        </div>
        <div className="metric">
          <div className="metric-l">Synced</div>
          <div className="metric-v">
            {txMetrics.total - txMetrics.pending}
            <span style={{ fontSize: 16, color: "var(--ink-3)" }}> / {txMetrics.total}</span>
          </div>
          <div className="metric-s">{txMetrics.pending} pending</div>
        </div>
      </div>

      {/* Gateway fee strip */}
      <div className="fee-strip">
        <div className="fee-lead">
          <div className="ic">
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8">
              <path d="M3 6h18v12H3z" />
              <path d="M3 10h18" />
              <path d="M7 15h4" />
            </svg>
          </div>
          <div>
            <div className="lbl">Gateway fees this month</div>
            <div className="amt">{fmtUSD(gatewayFees.thisMonth)}</div>
          </div>
        </div>
        <div className="fee-providers">
          {gatewayFees.providers.map((p) => (
            <div key={p.name} className="fee-prov">
              <span className="logo" style={{ background: p.brand }}>
                {p.name === "Stripe" ? "S" : "P"}
              </span>
              <div>
                <div className="pn">{p.name}</div>
                <div className="pv">{fmtUSD(p.amount)}</div>
                <div className="rate">{p.rate} · {p.charges} charges</div>
              </div>
            </div>
          ))}
        </div>
        <div className="fee-arg">
          <p>
            A <b>blended 2.5%</b> skimmed off every sale before it reaches you — invisible on the order line, real on the bank statement.
          </p>
        </div>
      </div>

      {/* AI strip */}
      <AIStrip label={txAI.label} meta={txAI.meta} cards={txAI.cards} />

      {/* Ledger tools */}
      <div className="ledger-tools">
        <div className="pt-search">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round">
            <circle cx="11" cy="11" r="8" />
            <line x1="21" y1="21" x2="16.65" y2="16.65" />
          </svg>
          <input
            type="text"
            placeholder="Search description, transaction ID, category, or source…"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
          <span className="count">{rows.length} transactions</span>
        </div>
      </div>

      <div className="filter-bar">
        <button
          className={`filter-pill${dirFilter === "all" ? " on" : ""}`}
          onClick={() => setDirFilter("all")}
        >
          All movements
        </button>
        <button
          className={`filter-pill${dirFilter === "in" ? " on" : ""}`}
          onClick={() => setDirFilter("in")}
        >
          Money in
        </button>
        <button
          className={`filter-pill${dirFilter === "out" ? " on" : ""}`}
          onClick={() => setDirFilter("out")}
        >
          Money out
        </button>
        <button
          className={`filter-pill${syncFilter === "pend" ? " on" : ""}`}
          onClick={() => setSyncFilter((s) => (s === "pend" ? "all" : "pend"))}
        >
          Pending sync only
        </button>
      </div>

      {/* Ledger */}
      <div className="ledger">
        <div className="ledger-head">
          {(
            [
              { k: "date", l: "Date" },
              { k: "desc", l: "Description" },
              { k: "cat", l: "Category" },
              { k: "src", l: "Source" },
              { k: "sync", l: "Sync" },
              { k: "amt", l: "Amount", r: true },
            ] as Array<{ k: SortKey; l: string; r?: boolean }>
          ).map((col) => {
            const active = sortKey === col.k;
            return (
              <span
                key={col.k}
                className={`c${active ? " active" : ""}${col.r ? " r" : ""}`}
                onClick={() => handleSort(col.k)}
              >
                {col.l} <span className="sort-ar">{sortDir > 0 ? "↑" : "↓"}</span>
              </span>
            );
          })}
        </div>

        {rows.length === 0 ? (
          <div className="ledger-empty">No transactions match this view</div>
        ) : (
          rows.map((t: Transaction) => {
            const sign = t.dir === "in" ? "+" : "−";
            const cls = t.dir === "in" ? "in" : "out";
            return (
              <div key={t.id} className={`lrow${t.fee ? " is-fee" : ""}`}>
                <span className="date">
                  {t.date} <span className="yr">{t.year}</span>
                </span>
                <div className="desc">
                  <span className="lbl">{t.desc}</span>
                  <div className="id">{t.detail}</div>
                </div>
                <span>
                  <span className={`cat-badge ${categoryBadge(t.category)}`}>
                    {t.category}
                  </span>
                </span>
                <span className="source">{t.source}</span>
                <span className={`sync ${t.sync}`}>
                  {t.sync === "ok" ? (
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.4">
                      <path d="M5 12l5 5L20 6" />
                    </svg>
                  ) : (
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                      <circle cx="12" cy="12" r="8" />
                      <path d="M12 8v4l3 2" />
                    </svg>
                  )}
                  {t.sync === "ok" ? "Synced" : "Pending"}
                </span>
                <div className="amt">
                  <div className={`v ${cls}`}>
                    {sign}{fmtUSD(t.amount)}
                  </div>
                  {t.dir === "in" && t.net && t.net < t.amount && (
                    <div className="net">
                      less <b>{fmtUSD(t.amount - t.net)}</b> gateway fee → {fmtUSD(t.net)} banked
                    </div>
                  )}
                </div>
              </div>
            );
          })
        )}

        <div className="ledger-foot">
          <span className="ct">
            Showing {rows.length} of {txMetrics.total}
          </span>
          <div className="foot-sums">
            <div className="foot-sum">
              <span className="l">Transactions</span>
              <span className="v">{rows.length}</span>
            </div>
            <div className="foot-sum">
              <span className="l">Money in</span>
              <span className="v in">+{fmtUSD(filteredIn)}</span>
            </div>
            <div className="foot-sum">
              <span className="l">Money out</span>
              <span className="v out">−{fmtUSD(filteredOut)}</span>
            </div>
            <div className="foot-sum">
              <span className="l">Net</span>
              <span className="v">
                {filteredNet >= 0 ? "+" : "−"}{fmtUSD(Math.abs(filteredNet))}
              </span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
